def import_schedule_data(apps, schema_editor):
    Client = apps.get_model('clients', 'Client')
    Task = apps.get_model('tasks', 'Task')
    Project = apps.get_model('projects', 'Project')
    User = apps.get_model('users', 'User')

    for item in CLIENTS:
        lookup = {}
        if item.get('phone'):
            lookup['phone'] = item['phone']
        if not lookup:
            lookup['name__iexact'] = item['name']
        Client.objects.get_or_create(defaults=item, **lookup)

    project, _ = Project.objects.get_or_create(
        name='Студия 313',
        defaults={'description': 'Клиенты и задачи Студии 313, импортированные из Excel'},
    )

    def get_or_create_editor(name):
        if not name:
            return None
        name = str(name).strip()
        if name.lower() in ('оутсорс', 'аутсорс', 'outsourcing'):
            return None
        user = User.objects.filter(first_name__iexact=name).first()
        if user:
            return user
        username = name.lower().replace(' ', '_') + '_mont'
        username = username[:150]
        base_username = username
        counter = 1
        while User.objects.filter(username=username).exists():
            suffix = f'_{counter}'
            username = base_username[:150 - len(suffix)] + suffix
            counter += 1
        return User.objects.create(
            username=username,
            first_name=name,
            role='staff',
            position='Монтажёр',
        )

    for item in TASKS:
        client = Client.objects.filter(name__iexact=item['client_name']).first()
        assignee = get_or_create_editor(item.pop('editor_name', None))
        item.pop('client_name', None)
        Task.objects.create(
            project=project,
            client=client,
            assignee=assignee,
            source='manual',
            **item
        )


